svg.script:
(function(){
  const root = document.documentElement;
  function setSelected(id,label){
    document.querySelectorAll('.semantic-object').forEach(n=>n.classList.remove('selected'));
    const el = document.getElementById(id);
    if (el) el.classList.add('selected');
    window.selectedObject = {id, label};
    try { window.parent.postMessage({type:'pt80-svg-click', objectId:id, label:label}, '*'); } catch(e) {}
  }
  document.querySelectorAll('.area-hit').forEach(function(el){
    el.addEventListener('click', function(evt){
      const id = el.getAttribute('data-object');
      const label = el.getAttribute('data-label') || id;
      setSelected(id, label);
      evt.stopPropagation();
    });
  });
})();
